nput-new-tag {\\r\\n    width: 250px;\\r\\n    margin-left: 10px;\\r\\n    vertical-align: bottom;\\r\\n}\\r\\n</style>\\r\\n<script>\\r\\nexport default {\\r\\n    props: [\\\"showDialog\\\", \\\"observations\\\", \\\"current\\\"],\\r\\n    data() {\\r\\n        return {\\r\\n            observation: null,\\r\\n            observationsArray: [],\\r\\n            newTag: null,\\r\\n            tags: [],\\r\\n            loading: false\\r\\n        };\\r\\n    },\\r\\n    mounted() {},\\r\\n    methods: {\\r\\n        search(input) {\\r\\n            this.tags = this.observations\\r\\n                .filter(o => o.description.includes(input.toUpperCase()))\\r\\n                .slice(0, 10);\\r\\n        },\\r\\n        addObservation() {\\r\\n            this.$emit(\\\"addObservation\\\", this.observation);\\r\\n            this.close();\\r\\n        },\\r\\n        async handleInputConfirm() {\\r\\n            if (this.newTag) {\\r\\n                if (this.newTag.trim().length > 1) {\\r\\n                    let toAdd = this.newTag.toUpperCase();\\r\\n\\r\\n                    try {\\r\\n                        this.loading = true;\\r\\n                        const response = await this.$http.post(\\r\\n                            \\\"../observations\\\",\\r\\n                            {\\r\\n                                description: toAdd,\\r\\n                                active: 1\\r\\n                            }\\r\\n                        );\\r\\n                        if (response.status == 200) {\\r\\n                            this.tags.push({\\r\\n                                description: toAdd,\\r\\n                                selected: true,\\r\\n                                active: 1\\r\\n                            });\\r\\n                            this.addWord(toAdd);\\r\\n                            this.formatObs();\\r\\n\\r\\n                            this.$emit(\\\"update:observations\\\", [\\r\\n                                ...this.observations,\\r\\n                                ...this.tags\\r\\n                            ]);\\r\\n                            this.tags = this.observations.slice(0, 10);\\r\\n                        } else {\\r\\n                            if (response.status == 422) {\\r\\n                                this.$toast.error(\\\"La obse ya existe.\\\");\\r\\n                            } else {\\r\\n                                this.$toast.error(\\\"No se guardó la obs.\\\");\\r\\n                            }\\r\\n                        }\\r\\n                    } catch (e) {\\r\\n                        console.log(e);\\r\\n                        const { response } = e;\\r\\n                        if (response.status == 422) {\\r\\n                            this.$toast.error(\\\"La observación ya existe.\\\");\\r\\n                        } else {\\r\\n                            this.$toast.error(\\\"No se guardó la obs.\\\");\\r\\n                        }\\r\\n                    } finally {\\r\\n                        this.loading = false;\\r\\n                    }\\r\\n                }\\r\\n            }\\r\\n\\r\\n            this.newTag = null;\\r\\n        },\\r\\n        select(idx) {\\r\\n            this.tags[idx].selected = !this.tags[idx].selected;\\r\\n            if (this.tags[idx].selected) {\\r\\n                this.addWord(this.tags[idx].description);\\r\\n            } else {\\r\\n                this.removeWord(this.tags[idx].description);\\r\\n            }\\r\\n            this.formatObs();\\r\\n        },\\r\\n        open() {\\r\\n            this.tags = this.observations.slice(0, 10).map(o => ({\\r\\n                ...o,\\r\\n                description: o.description.toUpperCase(),\\r\\n                selected: false\\r\\n            }));\\r\\n            this.observation = null;\\r\\n            this.observationsArray = [];\\r\\n            this.newTag = null;\\r\\n            if (this.current != null) {\\r\\n                if (this.current.length > 1) {\\r\\n                    this.observation = this.current;\\r\\n                    this.restore();\\r\\n                }\\r\\n            }\\r\\n        },\\r\\n        restore() {\\r\\n            let obs = this.observation.split(\\\" / \\\");\\r\\n            this.observationsArray = obs;\\r\\n            let tgs = this.tags.map(t => t.description);\\r\\n            let idxs = [];\\r\\n            for (let i = 0; i < tgs.length; i++) {\\r\\n                let wd = tgs[i];\\r\\n                if (obs.some(t => t == wd)) {\\r\\n                    idxs.push(i);\\r\\n                }\\r\\n            }\\r\\n            if (idxs.length != 0) {\\r\\n                idxs.forEach(i => {\\r\\n                    this.tags[i].selected = true;\\r\\n                });\\r\\n            }\\r\\n        },\\r\\n        close() {\\r\\n            this.$emit(\\\"update:showDialog\\\", false);\\r\\n        },\\r\\n        addWord(word) {\\r\\n            this.observationsArray.push(word);\\r\\n        },\\r\\n        removeWord(word) {\\r\\n            this.observationsArray = this.observationsArray.filter(\\r\\n                o => o != word\\r\\n            );\\r\\n        },\\r\\n        formatObs() {\\r\\n            this.observation = this.observationsArray.join(\\\" / \\\");\\r\\n        }\\r\\n    }\\r\\n};\\r\\n</script>\\r\\n\"],\"sourceRoot\":\"\"}]);\n\n// exports\n\n\n\n//////////////////\n// WEBPACK FOOTER\n// ./node_modules/css-loader?sourceMap!./node_modules/vue-loader/lib/style-compiler?{\"vue\":true,\"id\":\"data-v-24dace13\",\"scoped\":false,\"hasInlineConfig\":true}!./node_modules/vue-loader/lib/selector.js?type=styles&index=0!./modules/Restaurant/Resources/assets/js/views/partials/observation_form.vue\n// module id = ./node_modules/css-loader/index.js?sourceMap!./node_modules/vue-loader/lib/style-compiler/index.js?{\"vue\":true,\"id\":\"data-v-24dace13\",\"scoped\":false,\"hasInlineConfig\":true}